import { useEffect, useState } from "react";
import "./HackerDashboard.scss";

export default function HackerDashboard() {
  const [role, setRole] = useState("");
  const [username, setUsername] = useState("xploit_user");

  // 🔥 NEW
  const [activeFilter, setActiveFilter] = useState("all");
  const [bugs, setBugs] = useState([]);

  useEffect(() => {
    const storedRole = localStorage.getItem("role");
    const token = localStorage.getItem("token");
    const storedUser = localStorage.getItem("username");

    if (!token) {
      window.location.href = "/";
      return;
    }

    setRole(storedRole || "");
    if (storedUser) setUsername(storedUser);

    // 🔥 MOCK DATA (replace with API later)
    setBugs([
      {
        id: 1,
        title: "SQL Injection in Login API",
        severity: "High",
        status: "approved",
        reward: 2000,
      },
      {
        id: 2,
        title: "XSS in Profile Page",
        severity: "Medium",
        status: "submitted",
        reward: 0,
      },
      {
        id: 3,
        title: "CSRF on Payment Endpoint",
        severity: "Critical",
        status: "rejected",
        reward: 0,
      },
    ]);
  }, []);

  // 🔎 FILTER LOGIC
  const filteredBugs =
    activeFilter === "all"
      ? bugs
      : bugs.filter((bug) => bug.status === activeFilter);

  return (
    <div className="hacker-dashboard">
      {/* HEADER */}
      <header className="dashboard-header">
        <div>
          <h1 className="neon">🧑‍💻 Hacker Dashboard</h1>
          <p className="muted">
            @{username} | <span className="role">{role}</span>
          </p>
        </div>
        <div className="status">
          <span className="dot"></span> ONLINE
        </div>
      </header>

      {/* STATS (CLICKABLE) */}
      <section className="stats-grid">
        <div className="stat-card" onClick={() => setActiveFilter("submitted")}>
          <h3>🐞 Submitted</h3>
          <p>{bugs.filter((b) => b.status === "submitted").length}</p>
        </div>

        <div className="stat-card" onClick={() => setActiveFilter("approved")}>
          <h3>✅ Approved</h3>
          <p>{bugs.filter((b) => b.status === "approved").length}</p>
        </div>

        <div className="stat-card" onClick={() => setActiveFilter("rejected")}>
          <h3>❌ Rejected</h3>
          <p>{bugs.filter((b) => b.status === "rejected").length}</p>
        </div>

        <div className="stat-card" onClick={() => setActiveFilter("all")}>
          <h3>📄 My Bugs</h3>
          <p>{bugs.length}</p>
        </div>
      </section>

      {/* BUG LIST */}
      <section className="bug-list">
        <h2 className="neon">
          {activeFilter === "all"
            ? "My Bugs"
            : activeFilter.charAt(0).toUpperCase() +
              activeFilter.slice(1) +
              " Bugs"}
        </h2>

        {filteredBugs.length === 0 ? (
          <p className="muted">No bugs found.</p>
        ) : (
          filteredBugs.map((bug) => (
            <div key={bug.id} className={`bug-card ${bug.status}`}>
              <div>
                <h3>{bug.title}</h3>
                <p className="muted">
                  Severity: <strong>{bug.severity}</strong>
                </p>
              </div>

              <div className="bug-meta">
                <span className={`status-badge ${bug.status}`}>
                  {bug.status.toUpperCase()}
                </span>
                {bug.reward > 0 && (
                  <span className="reward">₹{bug.reward}</span>
                )}
              </div>
            </div>
          ))
        )}
      </section>

      {/* LOGOUT */}
      <button
        className="logout-btn"
        onClick={() => {
          localStorage.clear();
          window.location.href = "/";
        }}
      >
        🔒 Logout
      </button>
    </div>
  );
}
